const i = $input.first() ? ($input.first().json || {}) : {};
let t = (i.topic || i.query || i.text || '').toString().trim();
t = t.replace(/^\/[a-zA-Z]+\b/, '').trim();
if (!t) t = 'phishing';
return [{ json: { topic: t, date: new Date().toISOString().slice(0,10), client: ($env.CLIENT_NAME || '').toString() } }];

